from prometheus_client import Counter

CONTENT_ERROR_COUNTER = Counter(
    "llm_content_errors_total",
    "Content errors by type",
    ["error_type", "model"],
)

def record_completion(choice: dict, model: str):
    finish = choice.get("finish_reason", "unknown")
    content = (choice.get("message", {}).get("content") or "").strip()

    if finish == "length":
        CONTENT_ERROR_COUNTER.labels(error_type="truncated", model=model).inc()
    elif finish == "content_filter":
        CONTENT_ERROR_COUNTER.labels(error_type="content_filter", model=model).inc()
    elif not content and finish == "stop":
        CONTENT_ERROR_COUNTER.labels(error_type="empty_completion", model=model).inc()

import asyncio, httpx
from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception

RETRYABLE_STATUS = {429, 500, 502, 503, 504}

class RetryableError(Exception):
    pass

@retry(
    retry=retry_if_exception(lambda e: isinstance(e, RetryableError)),
    wait=wait_exponential(multiplier=1, min=1, max=16),
    stop=stop_after_attempt(4),
)
async def call_with_retry(client: httpx.AsyncClient, payload: dict) -> dict:
    try:
        r = await client.post("/v1/chat/completions", json=payload, timeout=30)
    except httpx.TimeoutException:
        raise RetryableError("Request timed out")

    if r.status_code in RETRYABLE_STATUS:
        raise RetryableError(f"HTTP {r.status_code}")
    if r.status_code == 400 and "max_tokens" in r.text:
        # Truncate prompt and retry once
        payload = {**payload, "max_tokens": payload.get("max_tokens", 512) // 2}
        raise RetryableError("Context too long, reducing max_tokens")
    r.raise_for_status()   # 4xx non-retryable: raise immediately
    return r.json()
